def filter_multiples(numbers):
    return [num for num in numbers if num % 2 == 0 and num % 3 == 0]

input_line = input().split()
numbers = [int(x) for x in input_line]
filtered_numbers = filter_multiples(numbers)

for i in range(len(filtered_numbers)):
    if i < len(filtered_numbers) - 1:
        print(filtered_numbers[i], end=" ")
    else:
        print(filtered_numbers[i])
